package kr.co.iei.report.model.service; import kr.co.iei.report.model.dao.ReportDao; import kr.co.iei.report.model.vo.*; import lombok.RequiredArgsConstructor; import org.springframework.stereotype.Service; @Service @RequiredArgsConstructor public class ReportServiceImpl implements ReportService { private final ReportDao reportDao; public void createReport(ReportRequest req){ Report r=new Report(); r.setReporterId(req.getReporterId()); r.setMeetingId(req.getMeetingId()); r.setTargetUserId(req.getTargetUserId()); r.setReason(req.getReason()); r.setContent(req.getContent()); reportDao.insertReport(r);} }
